<template>
  <div>
    <el-dialog
      :title="dialogTitle"
      :before-close="handleCancelLabelsDialog"
      :visible.sync="dialogIsShow"
      :show-close="false"
      width="30%"
    >
      <div>
        <el-radio-group
          v-model="notesModalType"
          size="small"
          class="result"
          @change="auditInit"
        >
          <el-radio-button label="pass">
            {{ resultInfo.pass_text }}
          </el-radio-button>
          <el-radio-button label="refuse">
            {{ resultInfo.refuse_text }}
          </el-radio-button>
        </el-radio-group>

        <div class="cont">
          <div
            v-if="notesModalType=='pass'"
            class="info"
            v-html="passInfo"
          />
          <div
            v-if="notesModalType=='refuse'"
            class="refuse-info"
          >
            <div class="text">
              拒絕原因
            </div>
            <el-input
              v-model="refuse_reason"
              type="textarea"
              :rows="2"
              maxlength="50"
              :show-word-limit="true"
              placeholder="非必填項，請填寫不超過50字。"
            />
          </div>

          <div
            v-if="auditdiff"
            class="check-hint"
          >
            <el-checkbox v-model="checkHint">
              <div
                class="tips"
                v-html="passTips"
              />
            </el-checkbox>
          </div>
        </div>
      </div>
      <div
        slot="footer"
      >
        <el-button
          type="primary"
          @click="handleAudit"
        >
          確認
        </el-button>
        <el-button @click="handleCancelLabelsDialog">
          取消
        </el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
export default {
  props: {
    auditType:String,
    dufStatus:String,
    auditdiff:Boolean,
    dialogIsShow:Boolean
  },
  data () {
    return {
      checkHint:false,
      refuse_reason:null,
      dialogTitle:null,
      notesModalType:'pass',
      resultInfo:{},
      passInfo:null,
      passTips:null
    }
  },
  computed: {
  },
  watch:{
    dialogIsShow:{
      handler (newValue, oldValue) {
        const {dufStatus} = this.$props;
        if(dufStatus!=null){
          this.$data.notesModalType = dufStatus;
        }
        this.auditInit();
      },
       immediate: true
    }
  },
  mounted () {
  //this.auditInit();
  },
  methods: {
    auditInit (){
      const {auditType,auditdiff} = this.$props;
      const {notesModalType} = this.$data;
      var dialogTitle = null;
      var passInfo = null;
      var passTips = null;
      var resultInfo = {};
      //console.log('auditInit',auditType,auditdiff,dufStatus);
      switch(auditType){
        case 'note':
          dialogTitle = '筆記審核';
          passInfo = '若筆記再三確認後無任何違規或敏感內容，點擊「確認」後將：</br></br>1. 筆記狀態將變為已通過，但可再次修改審核狀態；</br>2. 若用戶修改筆記，則該筆記需要再次審核。';
          passTips = '我已確認所選的筆記中 <span class="underline red">含有「非待審核」的筆記</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已通過」，小程序端將顯示筆記。</span>';
          if(notesModalType=='refuse'){
            passTips = '我已確認所選的筆記中 <span class="underline red">含有「非待審核」的筆記</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已拒絕」，小程序端將屏蔽筆記。</span>';
          }
          resultInfo = {pass_text:'發布所選',refuse_text:'下架所選'}
        break;
        case 'tag':
          dialogTitle = 'Tag審核';
          passInfo ='若Tag再三確認後無任何違規或敏感內容，點擊「確認」後將：</br></br>1. Tag狀態將變為已通過，但可再次修改審核狀態；</br>2. 用戶不可修改Tag。';
          passTips = '我已確認所選的Tag中 <span class="underline red">含有「非待審核」的Tag</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已通過」，小程序端將顯示Tag。</span>';
          resultInfo = {pass_text:'通過該Tag',refuse_text:'拒絕該Tag'}
          if(notesModalType=='refuse'){
            passTips = '我已確認所選的Tag中 <span class="underline red">含有「待審核」的Tag</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已拒絕」，小程序端將屏蔽Tag。</span>';
          }
          if(auditdiff){
            resultInfo = {pass_text:'通過所有',refuse_text:'拒絕所有'}
          }
        break;
        case 'topic':
          dialogTitle = '關聯話題審核';
          passInfo ='若話題內容再三確認後無任何違規或敏感內容，點擊「確認」後將：</br></br>1. 話題狀態將變為已通過，但可再次修改審核狀態；</br>2. 用戶更換話題不會影響該話題的狀態。';
          passTips = '我已確認所選的話題中<span class="underline red">含有「非待審核」的話題</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已通過」，小程序端將顯示話題。</span>';
          resultInfo = {pass_text:'通過該話題',refuse_text:'拒絕該話題'}
          if(notesModalType=='refuse'){
            passTips = '我已確認所選的話題中 <span class="underline red">含有「待審核」與「已通過」的話題</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已拒絕」，小程序端將屏蔽話題。</span>';
          }
          if(auditdiff){
            resultInfo = {pass_text:'通過所有',refuse_text:'拒絕所有'}
          }
        break;
        case 'review':
          dialogTitle = '評論審核';
          passInfo ='若評論再三確認後無任何違規或敏感內容，點擊「確認」後將：</br></br>1. 評論狀態將變為已通過，但可再次修改審核狀態；</br>2. 用戶不可修改評論。';
          passTips = '我已確認所選的評論中<span class="underline red">含有「非待審核」的評論</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已通過」，小程序端將顯示評論。</span>';
          resultInfo = {pass_text:'通過該評論',refuse_text:'拒絕該評論'}
          if(notesModalType=='refuse'){
            passTips = '我已確認所選的評論中 <span class="underline red">含有「待審核」的評論</span> ，</br> 並將通過此操作<span class="underline">變更狀態為「已拒絕」，小程序端將屏蔽評論。</span>';
          }
          if(auditdiff){
            resultInfo = {pass_text:'通過所有',refuse_text:'拒絕所有'}
          }
        break;
      }

      this.$data.dialogTitle = dialogTitle;
      this.$data.passInfo = passInfo;
      this.$data.passTips = passTips;
      this.$data.resultInfo = resultInfo;
    },
    handleCancelLabelsDialog () {
      this.$emit('cancelLabelsDialog',false)
    },
    handleAudit (){
      const {auditdiff} = this.$props;
      const {checkHint,refuse_reason,notesModalType} = this.$data;
      var params = {status:notesModalType=='pass'?1:4,refuse_reason}
      if(auditdiff && !checkHint){
        this.$message({
          type: 'error',
          message: '請勾選審核狀態知曉條目'
        })
        return false;
      }
      //console.log('handleAudit',params)
      this.$emit('notesAuditHandle',params)
    }
  }
}
</script>
<style scoped lang="css">
.result{position: absolute; top:20px; right: 20px;}
.btn-bar{margin-top: 30px; text-align: right;}
.refuse-info .text{margin-bottom: 20px;}
.check-hint{margin-top: 20px; }
.check-hint /deep/ .tips .underline{text-decoration: underline; color: #000; font-weight: bolder;}
.check-hint /deep/ .tips .underline.red{color: #f00}
.check-hint /deep/ .el-checkbox__label{vertical-align: middle;}
.check-hint /deep/ .el-checkbox__input.is-checked+.el-checkbox__label{color: #666;}
</style>
